1	type Cell = [number, number];
2	
3	const countNeighbors = (cell: Cell, cells: Cell[]): number =>
4	  cells.filter((candidate) => {
5	    const rowDiff = Math.abs(candidate[0] - cell[0]);
6	    const colDiff = Math.abs(candidate[1] - cell[1]);
7	    const isAdjacent = rowDiff <= 1 && colDiff <= 1;
8	    const isSameCell = rowDiff === 0 && colDiff === 0;
9	    return isAdjacent && !isSameCell;
10	  }).length;
11	
12	export function nextGeneration(cells: Cell[]): Cell[] {
13	  return cells.filter((cell) => {
14	    const neighborCount = countNeighbors(cell, cells);
15	    return neighborCount === 2 || neighborCount === 3;
16	  });
17	}
